import{_ as o,C as i,o as l,c as n,a5 as e,b as s,w as a,a as E,E as A,a4 as d}from"./chunks/framework.gGRxziV4.js";const _=JSON.parse('{"title":"Skill是什么","description":"","frontmatter":{},"headers":[],"relativePath":"05-Skill工程/01-Skill是什么.md","filePath":"05-Skill工程/01-Skill是什么.md","lastUpdated":1774181700000}'),h={name:"05-Skill工程/01-Skill是什么.md"};function g(k,t,p,u,S,B){const r=i("Mermaid");return l(),n("div",null,[t[1]||(t[1]=e('<h1 id="skill是什么" tabindex="-1">Skill是什么 <a class="header-anchor" href="#skill是什么" aria-label="Permalink to &quot;Skill是什么&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 5 模块的第 1 章。</p></blockquote><p>Skill 是让 Agent 从会聊天到能做事的能力模块——由指令、脚本和资源组成的结构化文件夹。</p><hr><h2 id="agent-缺少的关键能力" tabindex="-1">Agent 缺少的关键能力 <a class="header-anchor" href="#agent-缺少的关键能力" aria-label="Permalink to &quot;Agent 缺少的关键能力&quot;">​</a></h2><p>Agent 在执行真实世界任务时面临两个巨大的能力差距：</p><p><strong>缺乏过程知识</strong>——不知道事情该怎么做。就像一个聪明但没经验的新员工问&quot;我们的报销流程是什么？&quot;&quot;我该如何提交代码？&quot;</p><p><strong>缺乏组织背景</strong>——不知道东西在哪里。&quot;项目 API 密钥在哪里？&quot;&quot;PRD 模板在哪儿？&quot;</p><p>没有这两样东西，Agent 就无法处理真实世界中的具体工作。</p><hr><h2 id="skill-的定义" tabindex="-1">Skill 的定义 <a class="header-anchor" href="#skill-的定义" aria-label="Permalink to &quot;Skill 的定义&quot;">​</a></h2><p>Skill 是由指令、脚本和资源组成的结构化文件夹，智能体能够动态发现并加载这些内容，以提升特定任务的表现。</p><h3 id="三要素" tabindex="-1">三要素 <a class="header-anchor" href="#三要素" aria-label="Permalink to &quot;三要素&quot;">​</a></h3>',13)),(l(),s(d,null,{default:a(()=>[A(r,{id:"mermaid-37",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BSkill%20%E8%83%BD%E5%8A%9B%E6%A8%A1%E5%9D%97%5D%20--%3E%20B%5BInstructions%20%E6%8C%87%E4%BB%A4%3Cbr%2F%3ESOP%20%E6%96%87%E5%AD%97%E6%8F%8F%E8%BF%B0%5D%0A%20%20%20%20A%20--%3E%20C%5BScripts%20%E8%84%9A%E6%9C%AC%3Cbr%2F%3E%E5%8F%AF%E6%89%A7%E8%A1%8C%E7%9A%84%20Python%20%E6%96%87%E4%BB%B6%5D%0A%20%20%20%20A%20--%3E%20D%5BResources%20%E8%B5%84%E6%BA%90%3Cbr%2F%3E%E9%85%8D%E7%BD%AE%E6%96%87%E4%BB%B6%2F%E6%A8%A1%E6%9D%BF%5D%0A%20%20%20%20B%20--%3E%20E%5B%E8%A7%A3%E5%86%B3%3A%20%E8%BF%87%E7%A8%8B%E7%9F%A5%E8%AF%86%3Cbr%2F%3E%E4%BA%8B%E6%83%85%E8%AF%A5%E6%80%8E%E4%B9%88%E5%81%9A%5D%0A%20%20%20%20C%20--%3E%20E%0A%20%20%20%20D%20--%3E%20F%5B%E8%A7%A3%E5%86%B3%3A%20%E7%BB%84%E7%BB%87%E8%83%8C%E6%99%AF%3Cbr%2F%3E%E4%B8%9C%E8%A5%BF%E5%9C%A8%E5%93%AA%E9%87%8C%5D%0A%20%20%20%20E%20--%3E%20G%5BAgent%20%E4%BB%8E%E4%BC%9A%E8%81%8A%E5%A4%A9%3Cbr%2F%3E%E5%8F%98%E6%88%90%E8%83%BD%E5%81%9A%E4%BA%8B%5D%0A%20%20%20%20F%20--%3E%20G%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[E(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e('<blockquote><p>💡 <strong>图解：</strong> 指令和脚本解决&quot;不知道怎么干&quot;，资源解决&quot;不知道东西在哪&quot;——两者缺一，Agent 就是聪明但无能的新员工。</p></blockquote><table tabindex="0"><thead><tr><th>要素</th><th>对应</th><th>解决什么问题</th></tr></thead><tbody><tr><td><strong>Instructions（指令）</strong></td><td>手册中的 SOP 文字</td><td>过程知识——告诉他如何一步步完成任务</td></tr><tr><td><strong>Scripts（脚本）</strong></td><td>需要执行的 Python 文件</td><td>过程知识——可执行的操作步骤</td></tr><tr><td><strong>Resources（资源）</strong></td><td>配置文件或模板（JSON、DOCX 等）</td><td>组织背景——执行过程中用到的参考材料</td></tr></tbody></table><p>过程知识的缺失由指令和脚本解决，组织背景的缺失由资源解决。</p><h3 id="动态发现与加载" tabindex="-1">动态发现与加载 <a class="header-anchor" href="#动态发现与加载" aria-label="Permalink to &quot;动态发现与加载&quot;">​</a></h3><p>定义的后半句同样关键：&quot;智能体能够<strong>动态发现并加载</strong>这些内容&quot;。Skill 不再被固定在系统提示中，而是可以被动态检索、挂载、使用。当 Agent 面对不同任务时，它会主动发现最相关的 Skills，加载其中的 SOP、脚本和模板。</p><p>Skill 不只是知识的存储单元，而是让 Agent 在特定场景下变得更专业的<strong>能力模块</strong>。</p><hr><h2 id="skill-vs-tool" tabindex="-1">Skill vs Tool <a class="header-anchor" href="#skill-vs-tool" aria-label="Permalink to &quot;Skill vs Tool&quot;">​</a></h2><p>Tool 是原子操作——搜索、读文件、调 API。Skill 是过程知识——如何组合多个 Tool 完成一个复杂任务。</p><p>一个 Skill 可能包含：一段描述整个工作流的指令、几个辅助执行的脚本、执行过程中用到的模板文件。Agent 拿到 Skill 后，就像拿到了一本操作手册——知道该怎么做、用什么工具、参考什么模板。</p><hr><h2 id="skill-的本质" tabindex="-1">Skill 的本质 <a class="header-anchor" href="#skill-的本质" aria-label="Permalink to &quot;Skill 的本质&quot;">​</a></h2><p>把一个 Agent 想象成一个聪明但没经验的新员工。这个新员工入职第一天什么都做不了，因为他面临两个巨大的能力差距。Skill 就是给新员工的标准化 SOP、入职指南或岗位手册——有了它，Agent 就能在特定场景下表现得像专家。</p><p>但和真正的手册不同，Skill 支持渐进式披露——不是一次性把所有内容塞给 Agent，而是让它按需发现和加载。这解决了上下文膨胀的问题，同时保留了完整的知识储备。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Agent 缺少过程知识和组织背景，Skill 解决这两个问题</li><li>Skill 三要素：Instructions（SOP）、Scripts（可执行步骤）、Resources（模板）</li><li>动态发现与加载：不再固定在 System Prompt 中</li><li>Skill vs Tool：Tool 是原子操作，Skill 是过程知识的组合</li><li>本质：给 Agent 的岗位手册，支持渐进式披露</li></ul><hr><p><strong>下一章</strong>: <a href="./02-渐进式披露.html">渐进式披露</a></p><hr><p><a href="/Hermes-Engineering-ai-agent-/">← 返回首页</a> | <a href="/Hermes-Engineering-ai-agent-/04-多Agent架构/">← 上一模块: 多Agent架构</a> | <a href="/Hermes-Engineering-ai-agent-/06-Agent评估/">下一模块: Agent评估 →</a></p>',21))])}const q=o(h,[["render",g]]);export{_ as __pageData,q as default};
